use std::ffi::OsString;
use std::path::{Path, PathBuf};

use clap::Parser;
use symphony::{config, workflow};

#[derive(Parser, Debug, Clone)]
#[command(
    name = "symphony",
    about = "Symphony orchestrator — polls Linear, dispatches Codex agent sessions"
)]
pub struct Cli {
    /// Path to WORKFLOW.md
    #[arg(default_value = "WORKFLOW.md")]
    pub workflow_path: String,

    /// HTTP server port
    #[arg(long)]
    pub port: Option<u16>,

    /// Log file root directory
    #[arg(long)]
    pub logs_root: Option<String>,

    /// Acknowledge that this runs without guardrails
    #[arg(long = "i-understand-that-this-will-be-running-without-the-usual-guardrails")]
    pub acknowledge_guardrails: bool,
}

pub trait BootstrapDeps {
    fn workflow_exists(&mut self, workflow_path: &Path) -> bool;
    fn startup_validate(&mut self, workflow_path: &Path) -> Result<(), String>;
    fn start_orchestrator(&mut self, workflow_path: &Path, cli: &Cli) -> Result<(), String>;
}

#[derive(Default)]
pub struct RuntimeBootstrapDeps;

impl BootstrapDeps for RuntimeBootstrapDeps {
    fn workflow_exists(&mut self, workflow_path: &Path) -> bool {
        workflow_path.is_file()
    }

    fn startup_validate(&mut self, workflow_path: &Path) -> Result<(), String> {
        let definition = workflow::parse_workflow(workflow_path)
            .map_err(|err| format!("failed to parse workflow: {err}"))?;

        let config = config::from_workflow(&definition.config)
            .map_err(|err| format!("failed to decode workflow config: {err}"))?;

        config::validate(&config).map_err(|err| format!("invalid startup config: {err}"))?;
        Ok(())
    }

    fn start_orchestrator(&mut self, _workflow_path: &Path, _cli: &Cli) -> Result<(), String> {
        Err("orchestrator startup is not implemented yet".to_string())
    }
}

pub fn parse_cli_from<I, T>(args: I) -> Result<Cli, clap::Error>
where
    I: IntoIterator<Item = T>,
    T: Into<OsString> + Clone,
{
    Cli::try_parse_from(args)
}

pub fn resolve_workflow_path(cli: &Cli) -> PathBuf {
    PathBuf::from(&cli.workflow_path)
}

pub fn execute_cli(cli: &Cli, deps: &mut dyn BootstrapDeps) -> Result<(), String> {
    let workflow_path = resolve_workflow_path(cli);

    if !deps.workflow_exists(&workflow_path) {
        return Err(format!(
            "workflow file not found: {}",
            workflow_path.display()
        ));
    }

    // Intentionally incomplete in T01:
    // - startup validation is not invoked yet
    // - orchestrator startup is not invoked yet
    Ok(())
}

#[tokio::main]
async fn main() {
    let cli = Cli::parse();
    let mut deps = RuntimeBootstrapDeps;

    if let Err(err) = execute_cli(&cli, &mut deps) {
        eprintln!("{err}");
        std::process::exit(1);
    }
}

#[path = "../src/main.rs"]
mod main_bin;

use std::path::Path;

use main_bin::{BootstrapDeps, Cli};

struct FakeDeps {
    calls: Vec<String>,
    workflow_exists: bool,
    startup_validate_result: Result<(), String>,
    start_orchestrator_result: Result<(), String>,
}

impl Default for FakeDeps {
    fn default() -> Self {
        Self {
            calls: vec![],
            workflow_exists: false,
            startup_validate_result: Ok(()),
            start_orchestrator_result: Ok(()),
        }
    }
}

impl FakeDeps {
    fn call_history(&self) -> &[String] {
        &self.calls
    }
}

impl BootstrapDeps for FakeDeps {
    fn workflow_exists(&mut self, workflow_path: &Path) -> bool {
        self.calls
            .push(format!("workflow_exists:{}", workflow_path.display()));
        self.workflow_exists
    }

    fn startup_validate(&mut self, workflow_path: &Path) -> Result<(), String> {
        self.calls
            .push(format!("startup_validate:{}", workflow_path.display()));
        self.startup_validate_result.clone()
    }

    fn start_orchestrator(&mut self, workflow_path: &Path, _cli: &Cli) -> Result<(), String> {
        self.calls
            .push(format!("start_orchestrator:{}", workflow_path.display()));
        self.start_orchestrator_result.clone()
    }
}

#[test]
fn test_default_workflow_path_is_workflow_md() {
    let parsed = main_bin::parse_cli_from(["symphony"]);
    assert!(parsed.is_ok(), "CLI parse should succeed: {parsed:?}");

    let workflow_path = parsed
        .ok()
        .map(|cli| cli.workflow_path)
        .unwrap_or_else(|| "<missing>".to_string());

    assert_eq!(
        workflow_path, "WORKFLOW.md",
        "missing positional workflow path should default to WORKFLOW.md"
    );
}

#[test]
fn test_positional_workflow_override_is_respected() {
    let parsed = main_bin::parse_cli_from(["symphony", "tmp/custom/WORKFLOW.md"]);
    assert!(parsed.is_ok(), "CLI parse should succeed: {parsed:?}");

    let workflow_path = parsed
        .ok()
        .map(|cli| cli.workflow_path)
        .unwrap_or_else(|| "<missing>".to_string());

    assert_eq!(
        workflow_path, "tmp/custom/WORKFLOW.md",
        "explicit positional workflow path should override default"
    );
}

#[test]
fn test_missing_workflow_path_returns_startup_failure() {
    let parsed = main_bin::parse_cli_from(["symphony", "missing/WORKFLOW.md"]);
    assert!(parsed.is_ok(), "CLI parse should succeed");
    let cli = parsed.ok().unwrap_or_else(|| Cli {
        workflow_path: "missing/WORKFLOW.md".to_string(),
        port: None,
        logs_root: None,
        acknowledge_guardrails: false,
    });

    let mut deps = FakeDeps {
        workflow_exists: false,
        ..FakeDeps::default()
    };

    let result = main_bin::execute_cli(&cli, &mut deps);
    assert!(
        result.is_err(),
        "missing workflow file should return startup error"
    );

    let message = result.err().unwrap_or_default();
    assert!(
        message.contains("workflow file not found"),
        "error should mention missing workflow path, got: {message}"
    );

    let called_validate = deps
        .call_history()
        .iter()
        .any(|call| call.starts_with("startup_validate:"));
    assert!(
        !called_validate,
        "startup validation should not run when workflow file does not exist"
    );
}

#[test]
fn test_startup_validation_failure_surfaces_error_and_stops_bootstrap() {
    let parsed = main_bin::parse_cli_from(["symphony", "WORKFLOW.md"]);
    assert!(parsed.is_ok(), "CLI parse should succeed");
    let cli = parsed.ok().unwrap_or_else(|| Cli {
        workflow_path: "WORKFLOW.md".to_string(),
        port: None,
        logs_root: None,
        acknowledge_guardrails: false,
    });

    let mut deps = FakeDeps {
        workflow_exists: true,
        startup_validate_result: Err("missing tracker.api_key".to_string()),
        start_orchestrator_result: Ok(()),
        ..FakeDeps::default()
    };

    let result = main_bin::execute_cli(&cli, &mut deps);
    assert!(
        result.is_err(),
        "startup validation errors must fail bootstrap with non-zero semantics"
    );

    let called_start = deps
        .call_history()
        .iter()
        .any(|call| call.starts_with("start_orchestrator:"));

    assert!(
        !called_start,
        "orchestrator startup must not be invoked after validation failure"
    );
}

#[test]
fn test_successful_bootstrap_invokes_orchestrator_start() {
    let parsed = main_bin::parse_cli_from(["symphony", "WORKFLOW.md"]);
    assert!(parsed.is_ok(), "CLI parse should succeed");
    let cli = parsed.ok().unwrap_or_else(|| Cli {
        workflow_path: "WORKFLOW.md".to_string(),
        port: None,
        logs_root: None,
        acknowledge_guardrails: false,
    });

    let mut deps = FakeDeps {
        workflow_exists: true,
        startup_validate_result: Ok(()),
        start_orchestrator_result: Ok(()),
        ..FakeDeps::default()
    };

    let result = main_bin::execute_cli(&cli, &mut deps);
    assert!(result.is_ok(), "valid bootstrap should succeed: {result:?}");

    assert_eq!(
        deps.call_history(),
        [
            "workflow_exists:WORKFLOW.md",
            "startup_validate:WORKFLOW.md",
            "start_orchestrator:WORKFLOW.md"
        ],
        "bootstrap should run existence check, startup validation, then orchestrator start"
    );
}

use chrono::Utc;
use std::collections::{BTreeMap, BTreeSet, HashMap, HashSet};
use std::future::Future;
use std::path::Path;

use crate::codex::app_server;
use crate::config;
use crate::domain::{
    AgentEvent, CodexTotals, Issue, OrchestratorSnapshot, OrchestratorState, PollingSnapshot,
    RateLimitInfo, RetryEntry, RetrySnapshotEntry, RunAttempt, ServiceConfig,
};
use crate::error::Result;
use crate::{prompt_builder, workspace};

pub const CONTINUATION_RETRY_DELAY_MS: i64 = 1_000;
pub const FAILURE_RETRY_BASE_MS: i64 = 10_000;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RetryKind {
    Continuation,
    Failure,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RuntimeEvent {
    StartupCleanup,
    Reconcile,
    Validate,
    Dispatch,
    ValidationSkippedDispatch,
    RetryScheduled {
        issue_id: String,
        attempt: u32,
        due_at_ms: i64,
        token: String,
        retry_kind: RetryKind,
    },
    RetryIgnoredStale {
        issue_id: String,
        token: String,
    },
    WorkerCompleted {
        issue_id: String,
        issue_identifier: String,
        session_id: Option<String>,
    },
    WorkerFailed {
        issue_id: String,
        issue_identifier: String,
        session_id: Option<String>,
        error: String,
    },
    WorkerStalled {
        issue_id: String,
        issue_identifier: String,
        session_id: Option<String>,
        elapsed_ms: i64,
    },
}

#[derive(Debug, Clone)]
pub struct TickResult {
    pub dispatched_issue_ids: Vec<String>,
    pub dispatch_skipped: bool,
}

#[derive(Debug, Clone)]
pub struct TurnMetrics {
    pub input_tokens: u64,
    pub output_tokens: u64,
    pub total_tokens: u64,
    pub rate_limits: Option<serde_json::Value>,
}

#[derive(Debug, Clone, Default)]
pub struct RetryContext {
    pub worker_host: Option<String>,
    pub workspace_path: Option<String>,
    pub session_id: Option<String>,
}

#[derive(Debug, Clone)]
pub enum WorkerCompletion {
    Completed,
    Failed { error: String },
}

pub trait OrchestratorPort {
    fn startup_terminal_issues(&mut self, terminal_states: &[String]) -> Result<Vec<Issue>>;

    fn reconcile_running_issues(&mut self, running_issue_ids: &[String]) -> Result<Vec<Issue>>;

    fn validate_dispatch_preflight(&mut self, config: &ServiceConfig) -> Result<()>;

    fn fetch_candidate_issues(&mut self) -> Result<Vec<Issue>>;

    fn refresh_issue(&mut self, issue_id: &str) -> Result<Option<Issue>>;
}

/// S06 runtime authority loop state.
///
/// The orchestrator is the single mutable owner of dispatch/reconcile/retry
/// state in this process. State mutation only happens through `&mut self`
/// methods (startup cleanup, tick, retry handlers).
pub struct Orchestrator {
    config: ServiceConfig,
    state: OrchestratorState,
    events: Vec<RuntimeEvent>,
    retry_tokens: HashMap<String, String>,
    worker_last_activity_ms: HashMap<String, i64>,
    worker_session_ids: HashMap<String, String>,
    /// Normalized running issue state cache used for per-state slot accounting.
    running_issue_states: HashMap<String, String>,
    next_retry_token: u64,
}

impl Orchestrator {
    pub fn new(config: ServiceConfig) -> Self {
        let poll_interval_ms = config.polling.interval_ms;
        let max_concurrent_agents = config.agent.max_concurrent_agents;

        Self {
            config,
            state: OrchestratorState {
                poll_interval_ms,
                max_concurrent_agents,
                running: HashMap::new(),
                claimed: std::collections::HashSet::new(),
                retry_attempts: HashMap::new(),
                completed: std::collections::HashSet::new(),
                codex_totals: CodexTotals::default(),
                codex_rate_limits: None,
            },
            events: vec![],
            retry_tokens: HashMap::new(),
            worker_last_activity_ms: HashMap::new(),
            worker_session_ids: HashMap::new(),
            running_issue_states: HashMap::new(),
            next_retry_token: 0,
        }
    }

    pub async fn run(&mut self) -> Result<()> {
        Ok(())
    }

    pub fn startup_cleanup(&mut self, port: &mut dyn OrchestratorPort) -> Result<()> {
        self.events.push(RuntimeEvent::StartupCleanup);
        tracing::info!(
            phase = "startup_cleanup",
            "running startup terminal cleanup"
        );

        let terminal_issues = port.startup_terminal_issues(&self.config.tracker.terminal_states)?;

        for issue in terminal_issues {
            self.mark_issue_terminal(&issue.id);
        }

        Ok(())
    }

    pub fn tick(&mut self, port: &mut dyn OrchestratorPort) -> Result<TickResult> {
        self.events.push(RuntimeEvent::Reconcile);
        tracing::info!(phase = "reconcile", "starting orchestrator tick phase");
        self.reconcile_running(port)?;

        self.events.push(RuntimeEvent::Validate);
        tracing::info!(phase = "validate", "starting orchestrator tick phase");

        if let Err(err) = config::validate(&self.config) {
            tracing::warn!(
                phase = "dispatch",
                reason = "preflight_invalid",
                error = %err,
                "dispatch skipped due to invalid effective config"
            );
            self.events.push(RuntimeEvent::ValidationSkippedDispatch);
            return Ok(TickResult {
                dispatched_issue_ids: vec![],
                dispatch_skipped: true,
            });
        }

        if let Err(err) = port.validate_dispatch_preflight(&self.config) {
            tracing::warn!(
                phase = "dispatch",
                reason = "preflight_invalid",
                error = %err,
                "dispatch skipped due to preflight validation failure"
            );
            self.events.push(RuntimeEvent::ValidationSkippedDispatch);
            return Ok(TickResult {
                dispatched_issue_ids: vec![],
                dispatch_skipped: true,
            });
        }

        self.events.push(RuntimeEvent::Dispatch);
        tracing::info!(phase = "dispatch", "starting orchestrator tick phase");

        let candidates = port.fetch_candidate_issues()?;
        let mut dispatched_issue_ids = vec![];

        for candidate in self.sort_issues_for_dispatch(candidates) {
            if self.available_slots() == 0 {
                tracing::debug!(
                    phase = "dispatch",
                    reason = "slot_full",
                    "global concurrency slots exhausted"
                );
                break;
            }

            if !self.should_dispatch_issue(&candidate) {
                tracing::debug!(
                    phase = "dispatch",
                    reason = "blocked",
                    issue_id = %candidate.id,
                    issue_identifier = %candidate.identifier,
                    "candidate rejected before refresh"
                );
                continue;
            }

            let Some(refreshed_issue) = port.refresh_issue(&candidate.id)? else {
                tracing::debug!(
                    phase = "dispatch",
                    reason = "blocked",
                    issue_id = %candidate.id,
                    issue_identifier = %candidate.identifier,
                    "candidate missing at pre-dispatch refresh"
                );
                continue;
            };

            if !self.should_dispatch_issue(&refreshed_issue) {
                tracing::debug!(
                    phase = "dispatch",
                    reason = "blocked",
                    issue_id = %refreshed_issue.id,
                    issue_identifier = %refreshed_issue.identifier,
                    "candidate rejected after pre-dispatch refresh"
                );
                continue;
            }

            let state_key = normalize_issue_state(&refreshed_issue.state);
            if !self.state_slot_available(&state_key) {
                tracing::debug!(
                    phase = "dispatch",
                    reason = "slot_full",
                    issue_id = %refreshed_issue.id,
                    issue_identifier = %refreshed_issue.identifier,
                    state = %state_key,
                    "state concurrency slots exhausted"
                );
                continue;
            }

            self.dispatch_issue(&refreshed_issue);
            dispatched_issue_ids.push(refreshed_issue.id);
        }

        Ok(TickResult {
            dispatched_issue_ids,
            dispatch_skipped: false,
        })
    }

    pub fn schedule_retry(
        &mut self,
        issue_id: &str,
        identifier: &str,
        attempt: u32,
        retry_kind: RetryKind,
        now_ms: i64,
        error: Option<String>,
    ) -> String {
        self.schedule_retry_with_context(
            issue_id,
            identifier,
            attempt,
            retry_kind,
            now_ms,
            error,
            RetryContext::default(),
        )
    }

    pub fn schedule_retry_with_context(
        &mut self,
        issue_id: &str,
        identifier: &str,
        attempt: u32,
        retry_kind: RetryKind,
        now_ms: i64,
        error: Option<String>,
        context: RetryContext,
    ) -> String {
        self.next_retry_token += 1;
        let token = format!("retry-{}", self.next_retry_token);
        let due_at_ms = now_ms + self.retry_delay_ms(retry_kind, attempt);

        self.retry_tokens
            .insert(issue_id.to_string(), token.clone());

        self.state.retry_attempts.insert(
            issue_id.to_string(),
            RetryEntry {
                issue_id: issue_id.to_string(),
                identifier: identifier.to_string(),
                attempt,
                due_at_ms,
                timer_handle: Some(token.clone()),
                error: error.clone(),
                worker_host: context.worker_host.clone(),
                workspace_path: context.workspace_path.clone(),
            },
        );

        if let Some(session_id) = context.session_id.as_ref() {
            self.worker_session_ids
                .insert(issue_id.to_string(), session_id.clone());
        }

        tracing::info!(
            event = "retry_scheduled",
            issue_id = %issue_id,
            issue_identifier = %identifier,
            retry_kind = ?retry_kind,
            attempt,
            due_at_ms,
            token = %token,
            session_id = context.session_id.as_deref().unwrap_or("n/a"),
            worker_host = context.worker_host.as_deref().unwrap_or("local"),
            workspace_path = context.workspace_path.as_deref().unwrap_or("n/a"),
            error = error.as_deref().unwrap_or(""),
            "queued issue retry"
        );

        self.events.push(RuntimeEvent::RetryScheduled {
            issue_id: issue_id.to_string(),
            attempt,
            due_at_ms,
            token: token.clone(),
            retry_kind,
        });

        token
    }

    pub fn fire_retry(&mut self, issue_id: &str, token: &str) -> bool {
        let Some(current_token) = self.retry_tokens.get(issue_id).cloned() else {
            return false;
        };

        if current_token != token {
            tracing::info!(
                event = "retry_ignored_stale",
                issue_id = %issue_id,
                token = %token,
                current_token = %current_token,
                "ignored stale retry timer firing"
            );

            self.events.push(RuntimeEvent::RetryIgnoredStale {
                issue_id: issue_id.to_string(),
                token: token.to_string(),
            });
            return false;
        }

        self.retry_tokens.remove(issue_id);
        self.state.retry_attempts.remove(issue_id).is_some()
    }

    pub fn record_worker_activity(&mut self, issue_id: &str, timestamp_ms: i64) {
        self.worker_last_activity_ms
            .insert(issue_id.to_string(), timestamp_ms);
    }

    pub fn ingest_agent_event(&mut self, issue_id: &str, event: &AgentEvent) {
        self.record_worker_activity(issue_id, event_timestamp_ms(event));

        if let Some(session_id) = event_session_id(event) {
            self.worker_session_ids
                .insert(issue_id.to_string(), session_id.to_string());
        }

        if let Some(run_attempt) = self.state.running.get_mut(issue_id) {
            match event {
                AgentEvent::TurnFailed { error, .. }
                | AgentEvent::TurnEndedWithError { error, .. }
                | AgentEvent::StartupFailed { error, .. } => {
                    run_attempt.status = "failed".to_string();
                    run_attempt.error = Some(error.clone());
                }
                AgentEvent::TurnCancelled { .. } => {
                    run_attempt.status = "cancelled".to_string();
                }
                _ => {}
            }
        }

        tracing::debug!(
            issue_id = %issue_id,
            session_id = self
                .worker_session_ids
                .get(issue_id)
                .map(String::as_str)
                .unwrap_or("n/a"),
            event = %event_name(event),
            "ingested codex worker event"
        );
    }

    pub fn handle_worker_completion(
        &mut self,
        issue_id: &str,
        completion: WorkerCompletion,
        now_ms: i64,
    ) -> Option<String> {
        let run_attempt = self.state.running.remove(issue_id)?;
        self.state.claimed.remove(issue_id);
        self.running_issue_states.remove(issue_id);
        self.worker_last_activity_ms.remove(issue_id);

        let issue_identifier = run_attempt.issue_identifier.clone();
        let session_id = self.worker_session_ids.remove(issue_id);
        let retry_context = RetryContext {
            worker_host: run_attempt.worker_host.clone(),
            workspace_path: Some(run_attempt.workspace_path.clone()),
            session_id: session_id.clone(),
        };

        match completion {
            WorkerCompletion::Completed => {
                self.state.completed.insert(issue_id.to_string());

                tracing::info!(
                    event = "worker_completed",
                    issue_id = %issue_id,
                    issue_identifier = %issue_identifier,
                    session_id = session_id.as_deref().unwrap_or("n/a"),
                    "worker attempt completed; scheduling continuation retry"
                );

                self.events.push(RuntimeEvent::WorkerCompleted {
                    issue_id: issue_id.to_string(),
                    issue_identifier: issue_identifier.clone(),
                    session_id,
                });

                Some(self.schedule_retry_with_context(
                    issue_id,
                    &issue_identifier,
                    1,
                    RetryKind::Continuation,
                    now_ms,
                    None,
                    retry_context,
                ))
            }
            WorkerCompletion::Failed { error } => {
                self.state.completed.remove(issue_id);

                let attempt = run_attempt.attempt.unwrap_or(0).saturating_add(1).max(1);

                tracing::warn!(
                    event = "worker_failed",
                    issue_id = %issue_id,
                    issue_identifier = %issue_identifier,
                    session_id = session_id.as_deref().unwrap_or("n/a"),
                    attempt,
                    error = %error,
                    "worker attempt failed; scheduling failure retry"
                );

                self.events.push(RuntimeEvent::WorkerFailed {
                    issue_id: issue_id.to_string(),
                    issue_identifier: issue_identifier.clone(),
                    session_id,
                    error: error.clone(),
                });

                Some(self.schedule_retry_with_context(
                    issue_id,
                    &issue_identifier,
                    attempt,
                    RetryKind::Failure,
                    now_ms,
                    Some(error),
                    retry_context,
                ))
            }
        }
    }

    pub async fn execute_worker_attempt<E, EFut>(
        &mut self,
        issue: &Issue,
        prompt_template: &str,
        attempt: Option<u32>,
        graphql_executor: E,
    ) -> Result<()>
    where
        E: Fn(String, serde_json::Value) -> EFut + Clone + Send,
        EFut: Future<Output = Result<serde_json::Value>> + Send,
    {
        let workspace_info = workspace::ensure_workspace(
            &issue.identifier,
            &self.config.workspace,
            &self.config.hooks,
        )?;

        self.state.running.insert(
            issue.id.clone(),
            RunAttempt {
                issue_id: issue.id.clone(),
                issue_identifier: issue.identifier.clone(),
                attempt,
                workspace_path: workspace_info.path.clone(),
                started_at: Utc::now(),
                status: "running".to_string(),
                error: None,
                worker_host: None,
            },
        );
        self.state.claimed.insert(issue.id.clone());
        self.running_issue_states
            .insert(issue.id.clone(), normalize_issue_state(&issue.state));
        self.state.retry_attempts.remove(&issue.id);

        let workspace_path = Path::new(&workspace_info.path);
        if let Err(err) = workspace::run_before_run_hook(workspace_path, &self.config.hooks) {
            self.handle_worker_completion(
                &issue.id,
                WorkerCompletion::Failed {
                    error: err.to_string(),
                },
                Utc::now().timestamp_millis(),
            );
            return Err(err);
        }

        let prompt = match prompt_builder::render_prompt(prompt_template, issue, attempt) {
            Ok(prompt) => prompt,
            Err(err) => {
                self.handle_worker_completion(
                    &issue.id,
                    WorkerCompletion::Failed {
                        error: err.to_string(),
                    },
                    Utc::now().timestamp_millis(),
                );
                return Err(err);
            }
        };

        let mut session = match app_server::start_session(
            &self.config.codex,
            issue,
            workspace_path,
            Path::new(&self.config.workspace.root),
        )
        .await
        {
            Ok(session) => session,
            Err(err) => {
                self.handle_worker_completion(
                    &issue.id,
                    WorkerCompletion::Failed {
                        error: err.to_string(),
                    },
                    Utc::now().timestamp_millis(),
                );
                return Err(err);
            }
        };

        tracing::info!(
            event = "worker_started",
            issue_id = %issue.id,
            issue_identifier = %issue.identifier,
            session_id = %session.session_id,
            workspace_path = %workspace_info.path,
            "worker attempt started"
        );

        let mut observed_events: Vec<AgentEvent> = Vec::new();
        let run_result = app_server::run_turn(&mut session, &prompt, graphql_executor, |event| {
            observed_events.push(event);
        })
        .await;

        for event in &observed_events {
            self.ingest_agent_event(&issue.id, event);
        }

        if let Err(err) = app_server::stop_session(session).await {
            tracing::warn!(
                issue_id = %issue.id,
                issue_identifier = %issue.identifier,
                error = %err,
                "failed to stop codex session cleanly"
            );
        }

        let _ = workspace::run_after_run_hook(workspace_path, &self.config.hooks);

        match run_result {
            Ok(turn_result) => {
                self.apply_turn_metrics(&TurnMetrics {
                    input_tokens: turn_result.input_tokens,
                    output_tokens: turn_result.output_tokens,
                    total_tokens: turn_result.total_tokens,
                    rate_limits: turn_result.rate_limits,
                });

                self.handle_worker_completion(
                    &issue.id,
                    WorkerCompletion::Completed,
                    Utc::now().timestamp_millis(),
                );

                Ok(())
            }
            Err(err) => {
                self.handle_worker_completion(
                    &issue.id,
                    WorkerCompletion::Failed {
                        error: err.to_string(),
                    },
                    Utc::now().timestamp_millis(),
                );
                Err(err)
            }
        }
    }

    pub fn detect_stalled_workers(&mut self, now_ms: i64, stall_timeout_ms: i64) {
        if stall_timeout_ms <= 0 {
            return;
        }

        let running_issue_ids: Vec<String> = self.state.running.keys().cloned().collect();

        for issue_id in running_issue_ids {
            let Some(run_attempt) = self.state.running.get(&issue_id).cloned() else {
                continue;
            };

            let last_activity_ms = self
                .worker_last_activity_ms
                .get(&issue_id)
                .copied()
                .unwrap_or_else(|| run_attempt.started_at.timestamp_millis());

            let elapsed_ms = now_ms.saturating_sub(last_activity_ms);
            if elapsed_ms <= stall_timeout_ms {
                continue;
            }

            let session_id = self.worker_session_ids.get(&issue_id).cloned();

            tracing::warn!(
                event = "worker_stalled",
                issue_id = %issue_id,
                issue_identifier = %run_attempt.issue_identifier,
                session_id = session_id.as_deref().unwrap_or("n/a"),
                elapsed_ms,
                stall_timeout_ms,
                "detected stalled worker; scheduling failure retry"
            );

            self.events.push(RuntimeEvent::WorkerStalled {
                issue_id: issue_id.clone(),
                issue_identifier: run_attempt.issue_identifier.clone(),
                session_id,
                elapsed_ms,
            });

            self.handle_worker_completion(
                &issue_id,
                WorkerCompletion::Failed {
                    error: format!("stalled for {elapsed_ms}ms without codex activity"),
                },
                now_ms,
            );
        }
    }

    pub fn apply_turn_metrics(&mut self, metrics: &TurnMetrics) {
        self.state.codex_totals.input_tokens = self
            .state
            .codex_totals
            .input_tokens
            .saturating_add(metrics.input_tokens);
        self.state.codex_totals.output_tokens = self
            .state
            .codex_totals
            .output_tokens
            .saturating_add(metrics.output_tokens);
        self.state.codex_totals.total_tokens = self
            .state
            .codex_totals
            .total_tokens
            .saturating_add(metrics.total_tokens);

        if let Some(rate_limits) = metrics.rate_limits.clone() {
            self.state.codex_rate_limits = Some(rate_limit_info(rate_limits));
        }

        tracing::info!(
            event = "token_aggregate_updated",
            input_delta = metrics.input_tokens,
            output_delta = metrics.output_tokens,
            total_delta = metrics.total_tokens,
            input_total = self.state.codex_totals.input_tokens,
            output_total = self.state.codex_totals.output_tokens,
            total_total = self.state.codex_totals.total_tokens,
            has_rate_limits = metrics.rate_limits.is_some(),
            "updated codex aggregate token totals"
        );
    }

    pub fn events(&self) -> &[RuntimeEvent] {
        &self.events
    }

    pub fn state(&self) -> &OrchestratorState {
        &self.state
    }

    pub fn state_mut(&mut self) -> &mut OrchestratorState {
        &mut self.state
    }

    pub fn snapshot(&self, now_ms: i64) -> OrchestratorSnapshot {
        let running: BTreeMap<String, RunAttempt> = self
            .state
            .running
            .iter()
            .map(|(k, v)| (k.clone(), v.clone()))
            .collect();

        let claimed: BTreeSet<String> = self.state.claimed.iter().cloned().collect();
        let completed: BTreeSet<String> = self.state.completed.iter().cloned().collect();

        let mut retry_queue: Vec<RetrySnapshotEntry> = self
            .state
            .retry_attempts
            .values()
            .map(|entry| RetrySnapshotEntry {
                issue_id: entry.issue_id.clone(),
                identifier: entry.identifier.clone(),
                attempt: entry.attempt,
                due_in_ms: entry.due_at_ms - now_ms,
                error: entry.error.clone(),
                worker_host: entry.worker_host.clone(),
                workspace_path: entry.workspace_path.clone(),
            })
            .collect();

        retry_queue.sort_by(|a, b| {
            a.due_in_ms
                .cmp(&b.due_in_ms)
                .then_with(|| a.identifier.cmp(&b.identifier))
        });

        OrchestratorSnapshot {
            poll_interval_ms: self.state.poll_interval_ms,
            max_concurrent_agents: self.state.max_concurrent_agents,
            running,
            claimed,
            retry_queue,
            completed,
            codex_totals: self.state.codex_totals.clone(),
            codex_rate_limits: self.state.codex_rate_limits.clone(),
            polling: PollingSnapshot {
                checking: false,
                next_poll_in_ms: self.state.poll_interval_ms as i64,
                poll_interval_ms: self.state.poll_interval_ms,
            },
        }
    }

    fn reconcile_running(&mut self, port: &mut dyn OrchestratorPort) -> Result<()> {
        let running_issue_ids: Vec<String> = self.state.running.keys().cloned().collect();
        let refreshed_issues = port.reconcile_running_issues(&running_issue_ids)?;

        let terminal_states = self.terminal_state_set();
        let active_states = self.active_state_set();
        let mut visible_issue_ids: HashSet<String> = HashSet::new();

        for issue in refreshed_issues {
            visible_issue_ids.insert(issue.id.clone());

            let normalized_state = normalize_issue_state(&issue.state);
            if terminal_states.contains(&normalized_state) {
                self.mark_issue_terminal(&issue.id);
                continue;
            }

            if !issue.assigned_to_worker || !active_states.contains(&normalized_state) {
                self.release_issue(&issue.id);
                continue;
            }

            self.running_issue_states
                .insert(issue.id.clone(), normalized_state);
        }

        for running_id in running_issue_ids {
            if !visible_issue_ids.contains(&running_id) {
                self.release_issue(&running_id);
            }
        }

        Ok(())
    }

    fn sort_issues_for_dispatch(&self, mut issues: Vec<Issue>) -> Vec<Issue> {
        issues.sort_by(|a, b| {
            priority_rank(a.priority)
                .cmp(&priority_rank(b.priority))
                .then_with(|| issue_created_at_sort_key(a).cmp(&issue_created_at_sort_key(b)))
                .then_with(|| issue_identifier_sort_key(a).cmp(&issue_identifier_sort_key(b)))
        });

        issues
    }

    fn should_dispatch_issue(&self, issue: &Issue) -> bool {
        if !issue_has_required_fields(issue) {
            return false;
        }

        if !issue.assigned_to_worker {
            return false;
        }

        let normalized_state = normalize_issue_state(&issue.state);

        if self.terminal_state_set().contains(&normalized_state) {
            return false;
        }

        if !self.active_state_set().contains(&normalized_state) {
            return false;
        }

        if self.todo_issue_blocked_by_non_terminal(issue) {
            return false;
        }

        if self.state.claimed.contains(&issue.id)
            || self.state.running.contains_key(&issue.id)
            || self.state.completed.contains(&issue.id)
        {
            return false;
        }

        if self.available_slots() == 0 {
            return false;
        }

        self.state_slot_available(&normalized_state)
    }

    fn todo_issue_blocked_by_non_terminal(&self, issue: &Issue) -> bool {
        if normalize_issue_state(&issue.state) != "todo" {
            return false;
        }

        let terminal_states = self.terminal_state_set();

        issue.blocked_by.iter().any(|blocker| {
            blocker
                .state
                .as_ref()
                .map(|state| !terminal_states.contains(&normalize_issue_state(state)))
                .unwrap_or(true)
        })
    }

    fn available_slots(&self) -> u32 {
        self.state
            .max_concurrent_agents
            .saturating_sub(self.state.running.len() as u32)
    }

    fn state_slot_available(&self, state_key: &str) -> bool {
        let limit = self
            .config
            .agent
            .max_concurrent_agents_by_state
            .get(state_key)
            .copied()
            .unwrap_or(self.state.max_concurrent_agents);

        self.running_issue_count_for_state(state_key) < limit
    }

    fn running_issue_count_for_state(&self, state_key: &str) -> u32 {
        self.state
            .running
            .keys()
            .filter(|issue_id| {
                self.running_issue_states
                    .get(*issue_id)
                    .map(|running_state| running_state == state_key)
                    .unwrap_or(false)
            })
            .count() as u32
    }

    fn retry_delay_ms(&self, retry_kind: RetryKind, attempt: u32) -> i64 {
        match retry_kind {
            RetryKind::Continuation => CONTINUATION_RETRY_DELAY_MS,
            RetryKind::Failure => {
                let max_backoff_ms =
                    self.config.agent.max_retry_backoff_ms.min(i64::MAX as u64) as i64;
                let safe_attempt = attempt.max(1);
                let power = safe_attempt.saturating_sub(1).min(10);
                let exponential = FAILURE_RETRY_BASE_MS.saturating_mul(1_i64 << power);
                exponential.min(max_backoff_ms)
            }
        }
    }

    fn dispatch_issue(&mut self, issue: &Issue) {
        let attempt = RunAttempt {
            issue_id: issue.id.clone(),
            issue_identifier: issue.identifier.clone(),
            attempt: None,
            workspace_path: "/tmp/symphony-workspace-placeholder".to_string(),
            started_at: Utc::now(),
            status: "running".to_string(),
            error: None,
            worker_host: None,
        };

        self.state.running.insert(issue.id.clone(), attempt);
        self.state.claimed.insert(issue.id.clone());
        self.state.retry_attempts.remove(&issue.id);
        self.running_issue_states
            .insert(issue.id.clone(), normalize_issue_state(&issue.state));
    }

    fn mark_issue_terminal(&mut self, issue_id: &str) {
        self.state.completed.insert(issue_id.to_string());
        self.state.running.remove(issue_id);
        self.state.claimed.remove(issue_id);
        self.state.retry_attempts.remove(issue_id);
        self.running_issue_states.remove(issue_id);
        self.retry_tokens.remove(issue_id);
        self.worker_last_activity_ms.remove(issue_id);
        self.worker_session_ids.remove(issue_id);
    }

    fn release_issue(&mut self, issue_id: &str) {
        self.state.running.remove(issue_id);
        self.state.claimed.remove(issue_id);
        self.state.retry_attempts.remove(issue_id);
        self.running_issue_states.remove(issue_id);
        self.retry_tokens.remove(issue_id);
        self.worker_last_activity_ms.remove(issue_id);
        self.worker_session_ids.remove(issue_id);
    }

    fn active_state_set(&self) -> HashSet<String> {
        self.config
            .tracker
            .active_states
            .iter()
            .map(|state| normalize_issue_state(state))
            .filter(|state| !state.is_empty())
            .collect()
    }

    fn terminal_state_set(&self) -> HashSet<String> {
        self.config
            .tracker
            .terminal_states
            .iter()
            .map(|state| normalize_issue_state(state))
            .filter(|state| !state.is_empty())
            .collect()
    }
}

fn event_timestamp_ms(event: &AgentEvent) -> i64 {
    match event {
        AgentEvent::SessionStarted { timestamp, .. }
        | AgentEvent::StartupFailed { timestamp, .. }
        | AgentEvent::TurnCompleted { timestamp, .. }
        | AgentEvent::TurnFailed { timestamp, .. }
        | AgentEvent::TurnCancelled { timestamp, .. }
        | AgentEvent::TurnEndedWithError { timestamp, .. }
        | AgentEvent::TurnInputRequired { timestamp, .. }
        | AgentEvent::ApprovalAutoApproved { timestamp, .. }
        | AgentEvent::ApprovalRequired { timestamp, .. }
        | AgentEvent::ToolCallCompleted { timestamp, .. }
        | AgentEvent::ToolCallFailed { timestamp, .. }
        | AgentEvent::ToolInputAutoAnswered { timestamp, .. }
        | AgentEvent::UnsupportedToolCall { timestamp, .. }
        | AgentEvent::Notification { timestamp, .. }
        | AgentEvent::OtherMessage { timestamp, .. }
        | AgentEvent::Malformed { timestamp, .. } => timestamp.timestamp_millis(),
    }
}

fn event_session_id(event: &AgentEvent) -> Option<&str> {
    match event {
        AgentEvent::SessionStarted { session_id, .. } => Some(session_id.as_str()),
        _ => None,
    }
}

fn event_name(event: &AgentEvent) -> &'static str {
    match event {
        AgentEvent::SessionStarted { .. } => "session_started",
        AgentEvent::StartupFailed { .. } => "startup_failed",
        AgentEvent::TurnCompleted { .. } => "turn_completed",
        AgentEvent::TurnFailed { .. } => "turn_failed",
        AgentEvent::TurnCancelled { .. } => "turn_cancelled",
        AgentEvent::TurnEndedWithError { .. } => "turn_ended_with_error",
        AgentEvent::TurnInputRequired { .. } => "turn_input_required",
        AgentEvent::ApprovalAutoApproved { .. } => "approval_auto_approved",
        AgentEvent::ApprovalRequired { .. } => "approval_required",
        AgentEvent::ToolCallCompleted { .. } => "tool_call_completed",
        AgentEvent::ToolCallFailed { .. } => "tool_call_failed",
        AgentEvent::ToolInputAutoAnswered { .. } => "tool_input_auto_answered",
        AgentEvent::UnsupportedToolCall { .. } => "unsupported_tool_call",
        AgentEvent::Notification { .. } => "notification",
        AgentEvent::OtherMessage { .. } => "other_message",
        AgentEvent::Malformed { .. } => "malformed",
    }
}

fn normalize_issue_state(state_name: &str) -> String {
    state_name.trim().to_ascii_lowercase()
}

fn issue_has_required_fields(issue: &Issue) -> bool {
    !issue.id.trim().is_empty()
        && !issue.identifier.trim().is_empty()
        && !issue.title.trim().is_empty()
        && !issue.state.trim().is_empty()
}

fn priority_rank(priority: Option<i32>) -> i32 {
    match priority {
        Some(value) if (1..=4).contains(&value) => value,
        _ => 5,
    }
}

fn issue_created_at_sort_key(issue: &Issue) -> i64 {
    issue
        .created_at
        .map(|created_at| created_at.timestamp_micros())
        .unwrap_or(i64::MAX)
}

fn issue_identifier_sort_key(issue: &Issue) -> (&str, &str) {
    (issue.identifier.as_str(), issue.id.as_str())
}

pub fn rate_limit_info(data: serde_json::Value) -> RateLimitInfo {
    RateLimitInfo { data }
}

// WorkflowStore — live-watched config store with hot-reload.
//
// Holds the current effective (WorkflowDefinition, ServiceConfig) under a
// std::sync::RwLock, runs a background thread that watches the workflow file
// via `notify::recommended_watcher`, debounces events (400 ms), and
// atomically reloads on change.  Invalid reloads keep the last-known-good
// config and log the error.
//
// A `force_reload()` async method provides the dispatch-preflight reload
// trigger.
//
// SECURITY: api_key values must never be emitted via tracing.  `ServiceConfig`
// is never logged directly — only field names are logged, never values.

use std::path::{Path, PathBuf};
use std::sync::{Arc, RwLock};
use std::time::Duration;

use notify::{RecommendedWatcher, RecursiveMode, Watcher};

use crate::domain::{ServiceConfig, WorkflowDefinition};
use crate::error::{Result, SymphonyError};
use crate::{config, workflow};

// ── Type alias ────────────────────────────────────────────────────────────────

type EffectiveConfig = (WorkflowDefinition, ServiceConfig);

// ── WorkflowStore ─────────────────────────────────────────────────────────────

/// Owns the parsed WORKFLOW.md and its derived [`ServiceConfig`], and
/// hot-reloads the file when it changes on disk.
///
/// Last-known-good semantics: a reload failure (parse error, invalid config)
/// leaves the previous config in place.  Call [`effective_config`] to obtain
/// a snapshot of the current state.
///
/// [`effective_config`]: WorkflowStore::effective_config
pub struct WorkflowStore {
    path: PathBuf,
    inner: Arc<RwLock<EffectiveConfig>>,
    /// Keeps the watcher alive for the lifetime of the store.
    /// Dropping it would stop file-system notifications.
    _watcher: RecommendedWatcher,
}

impl WorkflowStore {
    /// Construct a [`WorkflowStore`] from a WORKFLOW.md path.
    ///
    /// Parses the file immediately.  Returns an error if the initial parse or
    /// config extraction fails (fail-fast on syntax/shape errors).  Does NOT
    /// call `config::validate()` — validation is the orchestrator's
    /// dispatch-preflight responsibility; the store accepts any syntactically
    /// valid config to allow iterative hot-reload fixes without restarting.
    ///
    /// Starts a background thread that debounces file-system events and
    /// hot-reloads the config when the watched file changes.
    pub fn new(path: &Path) -> Result<Self> {
        // Canonicalize early so all internal comparisons (including notify
        // event paths) use the real filesystem path.  On macOS /tmp is a
        // symlink to /private/tmp; without this, direct equality checks against
        // notify-reported paths would fail.  Fall back to the original path if
        // canonicalization is unavailable (e.g., path does not exist yet).
        let path = path.canonicalize().unwrap_or_else(|_| path.to_path_buf());

        // ── 1. Load initial config — fail fast on parse/extraction errors ─
        let def = workflow::parse_workflow(&path)?;
        let cfg = config::from_workflow(&def.config)?;

        let inner: Arc<RwLock<EffectiveConfig>> = Arc::new(RwLock::new((def, cfg)));

        // ── 2. Set up mpsc channel for notify events ───────────────────────
        let (tx, rx) = std::sync::mpsc::channel::<notify::Event>();

        // ── 3. Create notify watcher ───────────────────────────────────────
        let watched_path = path.clone();
        let mut watcher = notify::recommended_watcher(move |res: notify::Result<notify::Event>| {
            match res {
                Ok(e) => {
                    if event_mentions_workflow(&e, &watched_path) {
                        // Best-effort send — receiver may be gone if store dropped.
                        let _ = tx.send(e);
                    }
                }
                Err(e) => {
                    // OS-level watcher failures (inotify limit, permission denied,
                    // FSEvents overflow, etc.) mean the watcher is permanently broken
                    // and hot-reload is dead until the process restarts.
                    tracing::error!(
                        reason = %e,
                        "file-system watcher error — hot-reload is disabled until restart"
                    );
                }
            }
        })
        .map_err(|e| SymphonyError::Other(format!("watcher creation failed: {e}")))?;

        // Watch the parent directory with non-recursive mode.
        // Watching the parent (rather than the file itself) covers editors and
        // tools that use atomic-rename writes (write to temp → rename).
        let watch_dir = path.parent().ok_or_else(|| {
            SymphonyError::Other(format!(
                "cannot determine parent directory for watch path: {}",
                path.display()
            ))
        })?;

        watcher
            .watch(watch_dir, RecursiveMode::NonRecursive)
            .map_err(|e| SymphonyError::Other(format!("watcher setup failed: {e}")))?;

        // ── 4. Spawn debounce thread ───────────────────────────────────────
        //
        // We use a plain std::thread (not tokio::spawn) so that the store
        // can be constructed in both sync (`#[test]`) and async
        // (`#[tokio::test]`) contexts without requiring an active tokio
        // runtime.
        {
            let path_t = path.clone();
            let inner_t = inner.clone();

            std::thread::spawn(move || {
                while rx.recv().is_ok() {
                    // Debounce: sleep 400 ms, then drain any events
                    // that arrived in the meantime, before reloading.
                    std::thread::sleep(Duration::from_millis(400));
                    while rx.try_recv().is_ok() {}

                    force_reload_inner(&path_t, &inner_t);
                    // Receiver error means the sender (watcher) was
                    // dropped — store has been destroyed, exit thread.
                }
            });
        }

        Ok(WorkflowStore {
            path,
            inner,
            _watcher: watcher,
        })
    }

    /// Return a snapshot of the current `(WorkflowDefinition, ServiceConfig)`.
    ///
    /// The snapshot is a clone — callers can inspect it freely without holding
    /// a lock.  This method is safe to call from both sync and async contexts.
    ///
    /// If the read lock is poisoned (another thread panicked while holding the
    /// write lock), the last-written value is recovered and returned rather
    /// than propagating a panic.
    pub fn effective_config(&self) -> EffectiveConfig {
        match self.inner.read() {
            Ok(guard) => guard.clone(),
            Err(poisoned) => {
                tracing::warn!(
                    "WorkflowStore read lock was poisoned — recovering last-known-good config"
                );
                poisoned.into_inner().clone()
            }
        }
    }

    /// Force an immediate reload of the workflow file, bypassing the debounce
    /// buffer.
    ///
    /// If the reload fails, the last-known-good config is preserved and the
    /// error is logged and returned to the caller.
    ///
    /// Useful as a dispatch-preflight check: the orchestrator can call this
    /// right before dispatching a new agent session to pick up any changes.
    ///
    /// NOTE: This method does NOT call `config::validate()`.  The orchestrator
    /// must call `config::validate(&store.effective_config().1)` separately as
    /// a dispatch preflight.  See D017.
    pub async fn force_reload(&self) -> Result<()> {
        let path = self.path.clone();
        let inner = self.inner.clone();
        tokio::task::spawn_blocking(move || match try_load(&path) {
            Ok(effective) => apply_effective(&path, &inner, effective),
            Err(e) => {
                tracing::error!(
                    path = %path.display(),
                    reason = %e,
                    "workflow reload failed — keeping last known good"
                );
                Err(e)
            }
        })
        .await
        .map_err(|e| SymphonyError::Other(format!("reload task panicked: {e}")))?
    }
}

// ── Internal helpers ──────────────────────────────────────────────────────────

/// Attempt to parse and extract config from the workflow file, then atomically
/// update the store.  On failure, log the error and keep the last-known-good
/// config.
fn force_reload_inner(path: &Path, inner: &Arc<RwLock<EffectiveConfig>>) {
    let result = try_load(path).and_then(|effective| apply_effective(path, inner, effective));
    if let Err(e) = result {
        tracing::error!(
            path = %path.display(),
            reason = %e,
            "workflow reload failed — keeping last known good"
        );
    }
}

fn apply_effective(
    path: &Path,
    inner: &Arc<RwLock<EffectiveConfig>>,
    effective: EffectiveConfig,
) -> Result<()> {
    let mut guard = match inner.write() {
        Ok(guard) => guard,
        Err(poisoned) => {
            tracing::warn!(
                path = %path.display(),
                "WorkflowStore write lock was poisoned — recovering and overwriting with fresh config"
            );
            poisoned.into_inner()
        }
    };
    *guard = effective;
    tracing::info!(
        path = %path.display(),
        "workflow reloaded successfully"
    );
    Ok(())
}

fn event_mentions_workflow(event: &notify::Event, workflow_path: &Path) -> bool {
    event
        .paths
        .iter()
        .any(|event_path| event_path_matches_workflow(event_path, workflow_path))
}

fn event_path_matches_workflow(event_path: &Path, workflow_path: &Path) -> bool {
    let same_filename = event_path.file_name() == workflow_path.file_name();
    event_path == workflow_path
        || event_path.ends_with(workflow_path)
        || (same_filename
            && matches!(
                (event_path.parent(), workflow_path.parent()),
                (Some(event_parent), Some(workflow_parent))
                    if event_parent == workflow_parent || event_parent.ends_with(workflow_parent)
            ))
}

/// Parse and extract — returning the full [`EffectiveConfig`] or an error.
///
/// Does not call `config::validate()` (validation is the orchestrator's
/// dispatch-preflight responsibility).  Does not touch the store state.
fn try_load(path: &Path) -> Result<EffectiveConfig> {
    let def = workflow::parse_workflow(path)?;
    let cfg = config::from_workflow(&def.config)?;
    Ok((def, cfg))
}

