// Workflow loader — parses WORKFLOW.md files into WorkflowDefinition.

use crate::domain::WorkflowDefinition;
use crate::error::{Result, SymphonyError};
use std::path::Path;

/// Parse a WORKFLOW.md file into a [`WorkflowDefinition`].
///
/// The file may optionally contain YAML front matter delimited by `---` lines.
/// Parsing rules:
///
/// - **Happy path**: lines between first and second `---` are YAML front
///   matter; everything after the second `---` is the prompt body (trimmed).
/// - **No delimiters**: fewer than two `---` lines → entire content becomes
///   the prompt template; config is an empty mapping.
/// - **Empty YAML**: front-matter block is empty or all-whitespace → config
///   is an empty mapping; no error.
/// - **Non-map YAML**: front-matter parses to a non-mapping value (e.g. a
///   sequence or scalar) → [`SymphonyError::WorkflowFrontMatterNotAMap`].
///
/// # Errors
/// - [`SymphonyError::WorkflowParseError`] — IO failure or YAML syntax error.
/// - [`SymphonyError::WorkflowFrontMatterNotAMap`] — front matter is valid
///   YAML but is not a mapping.
pub fn parse_workflow(path: &Path) -> Result<WorkflowDefinition> {
    // ── 1. Read file ──────────────────────────────────────────────────────
    let content = std::fs::read_to_string(path).map_err(|e| {
        SymphonyError::WorkflowParseError(format!("failed to read {}: {e}", path.display()))
    })?;

    // ── 2. Locate `---` delimiter lines ───────────────────────────────────
    let lines: Vec<&str> = content.lines().collect();
    let delimiter_indices: Vec<usize> = lines
        .iter()
        .enumerate()
        .filter(|(_, line)| line.trim_end() == "---")
        .map(|(i, _)| i)
        .collect();

    if delimiter_indices.len() < 2 || delimiter_indices[0] != 0 {
        // No-delimiter case: whole file becomes prompt with empty config.
        return Ok(WorkflowDefinition {
            config: serde_yaml::Value::Mapping(Default::default()),
            prompt_template: content.trim().to_string(),
        });
    }

    let first = delimiter_indices[0];
    let second = delimiter_indices[1];

    // ── 3. Split front matter and prompt body ─────────────────────────────
    let front_matter_str = lines[first + 1..second].join("\n");
    let prompt_body = lines[second + 1..].join("\n").trim().to_string();

    // ── 4. Parse YAML front matter ────────────────────────────────────────
    let parsed_value = if front_matter_str.trim().is_empty() {
        // Empty YAML block → default empty mapping, no error.
        serde_yaml::Value::Mapping(Default::default())
    } else {
        serde_yaml::from_str::<serde_yaml::Value>(&front_matter_str).map_err(|e| {
            SymphonyError::WorkflowParseError(format!(
                "YAML parse error in {}: {e}",
                path.display()
            ))
        })?
    };

    // ── 5. Validate that front matter is a mapping ────────────────────────
    if !matches!(parsed_value, serde_yaml::Value::Mapping(_)) {
        return Err(SymphonyError::WorkflowFrontMatterNotAMap);
    }

    Ok(WorkflowDefinition {
        config: parsed_value,
        prompt_template: prompt_body,
    })
}

// Config layer — typed extraction, env resolution, tilde expansion, and validation.
//
// Implements spec §5.3 defaults, $VAR env indirection, ~ home expansion,
// nil-dropping normalization, and field validation.
//
// SECURITY: api_key values must never be emitted via tracing.

use std::collections::HashMap;

use serde::Deserialize;
use serde_yaml::{Mapping, Value};

use crate::domain::{
    AgentConfig, ApiKey, CodexConfig, HooksConfig, PollingConfig, ServerConfig, ServiceConfig,
    TrackerConfig, WorkerConfig, WorkspaceConfig,
};
use crate::error::{Result, SymphonyError};

// ── Key normalization and null-dropping ───────────────────────────────────────

/// Recursively walk a YAML `Value`:
/// - coerce all mapping keys to `Value::String`
/// - drop mapping entries whose value is `Value::Null`
///
/// Note: only `agent.max_concurrent_agents_by_state` map keys are lowercased
/// (done separately in `from_workflow`).  General key casing is NOT changed.
fn normalize_keys(val: Value) -> Value {
    match val {
        Value::Mapping(map) => {
            let mut new_map = Mapping::new();
            for (k, v) in map {
                if v.is_null() {
                    continue; // drop null entries
                }
                let key_str = key_to_string(k);
                new_map.insert(Value::String(key_str), normalize_keys(v));
            }
            Value::Mapping(new_map)
        }
        Value::Sequence(seq) => Value::Sequence(seq.into_iter().map(normalize_keys).collect()),
        other => other,
    }
}

fn key_to_string(k: Value) -> String {
    match k {
        Value::String(s) => s,
        Value::Bool(b) => b.to_string(),
        Value::Number(n) => n.to_string(),
        Value::Null => "null".to_string(),
        // Sequence/Mapping keys are unusual; log a warning and fall back to
        // debug representation so the entry is preserved rather than silently
        // dropped, but the operator is notified.
        other => {
            tracing::warn!(
                key = ?other,
                "mapping key is not a scalar type — using debug representation; \
                 config sections with complex keys may not be extracted correctly"
            );
            format!("{other:?}")
        }
    }
}

// ── Env-var resolution ────────────────────────────────────────────────────────

/// Returns the bare variable name if `val` is a `$IDENTIFIER` reference
/// (starts with `$`, no `/`, spaces, or `:` — guards against partial paths
/// like `$HOME/x`).  Returns `None` for all other inputs.
fn env_reference_name(val: &str) -> Option<&str> {
    let var_name = val.strip_prefix('$')?;
    let is_bare_identifier = !var_name.is_empty()
        && !var_name.contains('/')
        && !var_name.contains(' ')
        && !var_name.contains(':');
    if is_bare_identifier {
        Some(var_name)
    } else {
        None
    }
}

/// Resolve a `$VAR` reference.
///
/// If `val` starts with `$` and the remainder is a non-empty identifier
/// (no `/`, spaces, or `:` — guards against partial paths like `$HOME/x`),
/// look up the env var.  Return the value if set and non-empty; otherwise
/// return an empty string.  For all other inputs return `val` unchanged.
///
/// Logs a warning when a `$VAR` reference is provided but the env var is not
/// set or is empty, giving operators a clear signal for the root cause of
/// subsequent validation failures.
fn resolve_env(val: &str) -> String {
    if let Some(var_name) = env_reference_name(val) {
        return match std::env::var(var_name) {
            Ok(v) if !v.is_empty() => v,
            Ok(_) => {
                tracing::warn!(
                    var = var_name,
                    "env var referenced in config is set but empty"
                );
                String::new()
            }
            Err(_) => {
                tracing::warn!(var = var_name, "env var referenced in config is not set");
                String::new()
            }
        };
    }
    val.to_string()
}

// ── Tilde expansion ───────────────────────────────────────────────────────────

/// Expand a leading `~` to `$HOME`.
///
/// `"~"` → `$HOME`; `"~/foo"` → `"$HOME/foo"`; anything else is returned
/// unchanged.
fn expand_tilde_with_home(val: &str, home: Option<&str>) -> String {
    if val == "~" || val.starts_with("~/") {
        match home {
            Some(home) if !home.is_empty() => {
                if val == "~" {
                    home.to_string()
                } else {
                    format!("{}{}", home, &val[1..])
                }
            }
            _ => val.to_string(),
        }
    } else {
        val.to_string()
    }
}

fn expand_tilde(val: &str) -> String {
    if val == "~" || val.starts_with("~/") {
        let home = std::env::var("HOME").ok();
        let home_ref = home.as_deref().filter(|h| !h.is_empty());
        if home_ref.is_none() {
            tracing::warn!(
                raw_path = val,
                "HOME is not set or empty; tilde in workspace.root will not be expanded \
                 — workspace path may be relative or invalid"
            );
        }
        expand_tilde_with_home(val, home_ref)
    } else {
        val.to_string()
    }
}

